```cpp
#include <cstdint>
#include <cstddef>
#include <utility>  // std::exchange

class DmaBuffer {
public:
    // Constructor: allocate aligned buffer for DMA
    explicit DmaBuffer(size_t size)
        : data_(new uint8_t[size]),
          size_(size),
          in_use_(false) {
        // In real systems: use aligned_alloc or a dedicated DMA heap
    }

    // Destructor: release only if we own it
    ~DmaBuffer() {
        if (data_) {
            // Cancel any pending DMA using this buffer before freeing
            if (in_use_) DMA_Abort(data_);
            delete[] data_;
        }
    }

    // === NO COPY — a DMA buffer has exactly one owner ===
    DmaBuffer(const DmaBuffer&)            = delete;
    DmaBuffer& operator=(const DmaBuffer&) = delete;

    // === MOVE: transfer ownership, leave source in safe "empty" state ===
    DmaBuffer(DmaBuffer&& other) noexcept
        : data_(std::exchange(other.data_, nullptr)),
          size_(std::exchange(other.size_, 0)),
          in_use_(std::exchange(other.in_use_, false)) {}

    DmaBuffer& operator=(DmaBuffer&& other) noexcept {
        if (this != &other) {
            // Release our current resource first
            if (data_) {
                if (in_use_) DMA_Abort(data_);
                delete[] data_;
            }
            data_    = std::exchange(other.data_, nullptr);
            size_    = std::exchange(other.size_, 0);
            in_use_  = std::exchange(other.in_use_, false);
        }
        return *this;
    }

    uint8_t* data()   const { return data_; }
    size_t   size()   const { return size_; }
    bool     valid()  const { return data_ != nullptr; }

    // Start DMA transfer — marks buffer as in use
    void start_transfer(uint32_t dest_addr) {
        in_use_ = true;
        DMA_Start(data_, dest_addr, size_);
    }

private:
    uint8_t* data_;
    size_t   size_;
    bool     in_use_;
};

// Usage:
DmaBuffer produce_buffer() {
    DmaBuffer buf(512);
    fill_sensor_data(buf.data(), buf.size());
    return buf;  // NRVO or move — no copy
}

void consume_buffer(DmaBuffer buf) {  // Takes ownership by value
    buf.start_transfer(UART_DR_ADDR);
    // buf destroyed at end of scope — DMA_Abort called if still in_use_
}

void pipeline() {
    DmaBuffer b = produce_buffer();
    consume_buffer(std::move(b));  // Explicit: ownership transferred
    // b.valid() == false here — accessing it is programmer error
}
```

**Why copy is deleted:**
If `DmaBuffer` were copyable, two objects would point to the same buffer. Starting a DMA transfer from one while the other also starts (or while a destructor runs) is undefined behavior — the hardware and CPU race on the same memory.

**std::exchange pattern:** `std::exchange(other.data_, nullptr)` atomically reads the old value and sets it to null. After a move, the source is in a valid but "empty" state: `data_ == nullptr`, so its destructor is a no-op.

**Embedded allocator note:** For production, DMA buffers often come from a fixed pool allocator aligned to cache-line boundaries, not `new[]`. The ownership pattern is identical — only the allocator changes.

