```cpp
#include <cstdint>
#include <cstddef>
#include <new>       // std::bad_alloc, placement new
#include <array>
#include <cstring>   // memset

// Fixed-size pool: N objects of type T, no dynamic allocation
template <typename T, size_t N>
class PoolAllocator {
public:
    static T* allocate() {
        for (size_t i = 0; i < N; ++i) {
            if (!used_[i]) {
                used_[i] = true;
                // Placement new: construct T in pre-allocated storage
                // Returns pointer to storage — caller calls constructor separately
                // OR we just return the raw storage for the class's operator new
                return reinterpret_cast<T*>(&pool_[i]);
            }
        }
        return nullptr;  // Pool exhausted
    }

    static void deallocate(T* ptr) {
        for (size_t i = 0; i < N; ++i) {
            if (reinterpret_cast<T*>(&pool_[i]) == ptr) {
                used_[i] = false;
                return;
            }
        }
    }

private:
    // aligned_storage: correctly aligned raw bytes for T, no construction
    using Storage = std::aligned_storage_t<sizeof(T), alignof(T)>;
    static std::array<Storage, N> pool_;
    static std::array<bool, N>    used_;
};

template <typename T, size_t N>
std::array<typename PoolAllocator<T,N>::Storage, N> PoolAllocator<T,N>::pool_{};

template <typename T, size_t N>
std::array<bool, N> PoolAllocator<T,N>::used_{};


// ---- Class that uses the pool via operator new/delete override ----
class CanMessage {
public:
    uint32_t id;
    uint8_t  data[8];
    uint8_t  dlc;

    CanMessage(uint32_t id_, const uint8_t* d, uint8_t len)
        : id(id_), dlc(len) {
        memcpy(data, d, len);
    }

    // Override new: use pool instead of heap
    static void* operator new(size_t sz) {
        (void)sz;  // We know the size — it's sizeof(CanMessage)
        void* ptr = pool_.allocate();
        if (!ptr) throw std::bad_alloc{};  // Or: assert/error code
        return ptr;
    }

    // Override delete: return to pool
    static void operator delete(void* ptr) noexcept {
        pool_.deallocate(static_cast<CanMessage*>(ptr));
    }

private:
    static PoolAllocator<CanMessage, 32> pool_;  // 32-message pool
};

PoolAllocator<CanMessage, 32> CanMessage::pool_{};


// Placement new example — constructing in caller-provided buffer:
void placement_new_example() {
    // Static buffer — no heap at all
    alignas(CanMessage) uint8_t raw_buf[sizeof(CanMessage)];

    uint8_t payload[] = {0x01, 0x02};
    // Construct CanMessage IN raw_buf — no allocation:
    CanMessage* msg = new (raw_buf) CanMessage(0x123, payload, 2);

    // Use msg normally...
    msg->id;  // 0x123

    // MUST call destructor manually — delete would try to free the stack buffer
    msg->~CanMessage();
}


// Normal usage with pool:
void enqueue_can() {
    uint8_t d[] = {0xDE, 0xAD};
    CanMessage* m = new CanMessage(0x7FF, d, 2);  // From pool, not heap
    // ... enqueue m ...
    delete m;  // Returns slot to pool
}
```

**Key concepts:**
- `std::aligned_storage_t<sizeof(T), alignof(T)>` provides correctly-aligned raw bytes without constructing T
- Placement new `new (ptr) T(args)` calls the constructor at a specific address — no allocation
- You **must** call the destructor manually (`ptr->~T()`) before reusing placement-new storage
- Overriding `operator new`/`delete` per-class routes ALL `new`/`delete` calls for that class through your pool
- The static pool lives in BSS — zero heap overhead, zero fragmentation

